import heapq

class Graph:
    def __init__(self):
        self.nodes = set()
        self.adj = {} # {node: {neighbor: weight}}

    def add_node(self, node):
        self.nodes.add(node)
        if node not in self.adj:
            self.adj[node] = {}

    def add_edge(self, u, v, weight):
        self.add_node(u)
        self.add_node(v)
        self.adj[u][v] = weight
        # Eğer grafik yönsüzse, şu satırı da ekleyin:
        # self.adj[v][u] = weight

    def dijkstra(self, start_node):
        if start_node not in self.nodes:
            raise ValueError(f"Başlangıç düğümü '{start_node}' grafikte bulunmuyor.")

        distances = {node: float('inf') for node in self.nodes}
        distances[start_node] = 0

        priority_queue = [(0, start_node)] # (mesafe, düğüm)

        predecessors = {node: None for node in self.nodes}

        while priority_queue:
            current_distance, current_node = heapq.heappop(priority_queue)

            # Bu yol mevcut en kısa yoldan daha uzunsa, bunu atla
            if current_distance > distances[current_node]:
                continue

            # Komşuları keşfet
            if current_node in self.adj:
                for neighbor, weight in self.adj[current_node].items():
                    distance = current_distance + weight

                    # Eğer daha kısa bir yol bulunursa
                    if distance < distances[neighbor]:
                        distances[neighbor] = distance
                        predecessors[neighbor] = current_node
                        heapq.heappush(priority_queue, (distance, neighbor))

        return distances, predecessors

# Örnek kullanım:
if __name__ == "__main__":
    graph = Graph()
    graph.add_edge('A', 'B', 1)
    graph.add_edge('A', 'C', 4)
    graph.add_edge('B', 'C', 2)
    graph.add_edge('B', 'D', 5)
    graph.add_edge('C', 'D', 1)
    graph.add_edge('D', 'E', 3)

    start_node = 'A'
    shortest_distances, paths = graph.dijkstra(start_node)

    print(f"'{start_node}' düğümünden diğer tüm düğümlere en kısa mesafeler:")
    for node, distance in shortest_distances.items():
        print(f"  {node}: {distance}")

    print("\nEn kısa yolların öncülleri:")
    for node, predecessor in paths.items():
        print(f"  {node}: {predecessor}")

    # Belirli bir hedefe giden yolu yeniden oluşturma örneği
    target_node = 'E'
    if target_node in paths and shortest_distances[target_node] != float('inf'):
        path = []
        current = target_node
        while current is not None:
            path.append(current)
            current = paths[current]
        path.reverse()
        print(f"\n'{start_node}'den '{target_node}'ye en kısa yol: {' -> '.join(path)}")
        print(f"Toplam mesafe: {shortest_distances[target_node]}")
    else:
        print(f"\n'{start_node}'den '{target_node}'ye bir yol bulunamadı.")

    # Yalıtılmış bir düğüm ekleyelim
    graph.add_node('F')
    shortest_distances, _ = graph.dijkstra(start_node)
    print(f"\n'F' düğümü eklendikten sonra 'A'dan mesafeler:")
    for node, distance in shortest_distances.items():
        print(f"  {node}: {distance}")
